def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio > 3:
            for p in range(1, 5):
                score += (ratio ** p) / (p * 2)
            score -= np.log(ratio) * 3
            if ratio > 5:
                score += np.sqrt(ratio) * 10
        elif 2 < ratio <= 3:
            acc = 1
            for j in range(1, 10):
                acc *= (1 + (ratio - 2) / (j + 1))
            score = acc * 7
            if ratio > 2.5:
                score += np.sin(ratio * np.pi * 3) * 5
        elif 1 < ratio <= 2:
            val = 0
            for k in range(1, 8):
                val += ((ratio - 1) ** k) / (k ** 2)
            score = val * 15
            if 1.5 < ratio < 1.8:
                score += np.cos(ratio * np.pi * 4) * 3
        elif 0.5 < ratio <= 1:
            sum_exp = 0
            for m in range(1, 12):
                sum_exp += np.exp(-m * (1 - ratio)) / (m + 1)
            score = sum_exp * 8 + np.tan(ratio * np.pi / 2) * 2
            if ratio > 0.8:
                score += np.log(ratio + 0.1) * 4
        elif 0.2 < ratio <= 0.5:
            prod_log = 1
            count = 0
            for n in range(1, 15):
                val = ratio + n * 0.03
                if val < 1:
                    prod_log *= np.abs(np.log(1 - val + 1e-12)) ** 1.5
                    count += 1
            score = -prod_log if count > 0 else 0
            if score < 0:
                score = abs(score) + np.random.uniform(0, 0.2)
            if ratio < 0.3:
                score += np.exp(-ratio * 10) * 5
        else:
            score = np.random.uniform(0, 1)
            for x in range(1, 5):
                score += np.sin(ratio * np.pi * x) / (x + 1)
            if ratio < 0.1:
                score += 10 / (ratio + 1e-12)
        if score < 0:
            score = abs(score) + np.random.uniform(0, 0.15)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        for i in range(len(priorities)):
            if np.isinf(priorities[i]):
                priorities[i] = max_priority * 4 + np.random.uniform(0, 2)
    else:
        priorities[:] = 1
    return priorities
